def replay_infosets(g):
    """Replays g.set_infoset(...) calls."""
    g.set_infoset(g.root.children['Bullet at chamber 2'], g.root.children['Bullet at chamber 1'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 3'], g.root.children['Bullet at chamber 1'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 3'].children['Pull'], g.root.children['Bullet at chamber 2'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 4'], g.root.children['Bullet at chamber 1'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 4'].children['Pull'], g.root.children['Bullet at chamber 2'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 4'].children['Pull'].children['Pull'], g.root.children['Bullet at chamber 3'].children['Pull'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 5'], g.root.children['Bullet at chamber 1'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 5'].children['Pull'], g.root.children['Bullet at chamber 2'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 5'].children['Pull'].children['Pull'], g.root.children['Bullet at chamber 3'].children['Pull'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 5'].children['Pull'].children['Pull'].children['Pull'], g.root.children['Bullet at chamber 4'].children['Pull'].children['Pull'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 6'], g.root.children['Bullet at chamber 1'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 6'].children['Pull'], g.root.children['Bullet at chamber 2'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 6'].children['Pull'].children['Pull'], g.root.children['Bullet at chamber 3'].children['Pull'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 6'].children['Pull'].children['Pull'].children['Pull'], g.root.children['Bullet at chamber 4'].children['Pull'].children['Pull'].children['Pull'].infoset)
    g.set_infoset(g.root.children['Bullet at chamber 6'].children['Pull'].children['Pull'].children['Pull'].children['Pull'], g.root.children['Bullet at chamber 5'].children['Pull'].children['Pull'].children['Pull'].children['Pull'].infoset)
